head.script:
scwin.CargoType = "cargo";

scwin.selectedLclRow = "";

// wfm_wframe2에서 setting해주는 변수 3종
scwin.selectedvehclRow = "";
scwin.vehclType = "";   
scwin.ez110Idx = "";

scwin.grdObj;

scwin.onpageload = function () {

    // 검색조건 - 컨테이너 탭에서만 보임
    grp_searchbox.hide();

    // grid object
    scwin.grdObj = gr_fl;

};

scwin.onUdcCompleted = function () {

    // 시스템메뉴 - 미리보기 기능
    if ($p.top().$p.isPopup()) {

        const title = $c.data.getParameter("menuInfo", $p.top().$p).popupName;
        wfm_header.getWindow().txt_h1.setValue(title);

        // $p.parent().wfm_wframe2.setSrc("/ui/bp/fbp/op/ac/ez_208_01_03b.xml");
        // return;
    }

    scwin.loadcomplete();
}

scwin.loadcomplete = async function() {

    const userId = $c.data.getMemInfo("userId");  //사용자ID

    if (userId === "acecorea") {

        // 윌로펌프 협력업체인 경우에만 정보가 노출
        const noVisibleCol = ["nrm","tplRmk","rclntOrdNo","onPos","offPos","col11","dmndNm","dlvyPlNm","lobranNm",
            "statuss","alloccarSts","openYn","dmCoshippingNo","ofcNm","clntNm","picNm","telNo","realClntNm","alloccarDd",
            "hirecarClntNm","vehclPicNm","vehclTelNo2","payAdvn","payDvly","defrAmt","strAmt","strAmtClntNm",
            "cmis","initAmt","prePayAmt","requestYn","regId","realOn","realOff","idx","dmWrkIndictNo","railroadAdptDstCd",
            "goods","qty","wt","unit"];

        for(let i=0; i<noVisibleCol.length; i++) {
            gr_fl.setColumnVisible(noVisibleCol[i], false);
        }

        lc_carAllocGub.setValue(1); // 

    } else {

        btn_showWiloOdrList.hide();
        lc_carAllocGub.hide();

        const noVisibleCol = ["vehclKndNm","vehclNrmNm","onReqDh","offReqDh","wiloYn","onNm","offNm","agntRate","gate","rmk2","realOnWt","realOnQty"];
        for(let i=0; i<noVisibleCol.length; i++) {
            gr_fl.setColumnVisible(noVisibleCol[i], false);
        }
    }

    dma_common.set("userId", userId);
    $c.sbm.setAction(sbm_common, "/ncall.bp.fbp.op.ac.cmd.RetrieveCondCMD.do");
    const ret = await $c.sbm.execute(sbm_common); 
    if (ret.responseJSON.resultDataSet[0].Code == 0) {
        ds_cond.setJSON(ret.responseJSON.GAUCE);

        if (ds_cond.getTotalRow() > 0) {

            // 컨테이너 탭 조회
            await scwin.search_cont();

        } else {
            // 조회조건 팝업 호출
            scwin.showsearchPop();
        }

        // 하단 wframe 호출
        await $p.parent().wfm_wframe2.setSrc("/ui/bp/fbp/op/ac/ez_208_01_03b.xml");
    }

};

/**
 * wframe2에서 오는 value
 */
scwin.selectedvehclRow_onchange = function (info) {
    scwin.selectedvehclRow = info.newValue;
};

/**
 * wframe2에서 오는 value
 */
scwin.vehclType_onchange = function (info) {
    scwin.vehclType = info.newValue;
};

/**
 * wframe2에서 오는 value
 */
scwin.ez110Idx_onchange = function (info) {
    scwin.ez110Idx = info.newValue;
};

/**
 * 벌크화물 탭 조회
 */
scwin.search_cargo = async function() {

    scwin.set_searchCondition("cargo");

    $c.sbm.setAction(sbm_retrieve, "/ncall.bp.fbp.op.ac.cmd.RetrieveBlkCMD.do");
    const ret = await $c.sbm.execute(sbm_retrieve);
    if (ret.responseJSON.resultDataSet[0].Code == 0) {
        ds_fl.setJSON(ret.responseJSON.GAUCE);

        for(let i=0; i<ds_fl.getTotalRow(); i++) {

            gr_fl.setRowReadOnly(i, true);

            // 그리드 초기화
            gr_fl.setRowBackgroundColor(i, "");

            // 글자색 변경
            if (ds_fl.getCellData(i, "statuss") === "대기") {
                gr_fl.setRowColor(i, "blue");
            } else {
                gr_fl.setRowColor(i, "black");
            }
        }
    }

};

/**
 * 컨테이너 탭 조회
 */
scwin.search_cont = async function() {

    scwin.set_searchCondition("cont");

    $c.sbm.setAction(sbm_retrieve, "/ncall.bp.fbp.op.ac.cmd.RetrieveCntrCMD.do");
    const ret = await $c.sbm.execute(sbm_retrieve);
    if (ret.responseJSON.resultDataSet[0].Code == 0) {
        ds_flc.setJSON(ret.responseJSON.GAUCE);

        tbx_totalCont.setValue(ds_flc.getTotalRow());

    }

};

/**
 * 조회조건 세팅
 */
scwin.set_searchCondition = function(type) {

    const {cargoDateTyp,cargoDateCnd,cargoDate1,cargoDate2,cargoSrchTyp,cargoSrchCnd,...rest} = ds_cond.getRowJSON(0);

    const {gsVl3,gsVl4} = scwin.set_dateByType(cargoDateTyp);

    const retrieveCondition = {
        cargoDateTyp: cargoDateTyp,
        cargoDateCnd: cargoDateCnd,
        cargoDate1: cargoDateTyp == "5"? cargoDate1 : gsVl3,
        cargoDate2: cargoDateTyp == "5"? cargoDate2 : gsVl4,
        cargoSrchTyp: cargoSrchTyp,    // 검색형태
        cargoSrchCnd: cargoSrchCnd,
        cargoSts1: rest.cargoSts1,
        cargoSts2: rest.cargoSts2,
        cargoSts3: rest.cargoSts3,
        cargoHdidx: rest.cargoHdidx,
        cargoBhidx: rest.cargoBhidx,
        cargoOfcidx: rest.cargoOfcidx,
        cargoOrd1: rest.cargoOrd1,
        cargoOrdAsc1: rest.cargoOrdAsc1,
        cargoOrdUsr1: rest.cargoOrdUsr1,
        cargoOrd2: rest.cargoOrd2,
        cargoOrdAsc2: rest.cargoOrdAsc2,
        cargoOrdUsr2: rest.cargoOrdUsr2,
        cargoOrd3: rest.cargoOrd3,
        cargoOrdAsc3: rest.cargoOrdAsc3,
        cargoOrdUsr3: rest.cargoOrdUsr3,
        caridx: "" || scwin.ez110Idx
    }

    let ord = 0;
    if (rest.cargoOrdUsr1 > 0) ord += 1;
    if (rest.cargoOrdUsr2 > 0) ord += 2;
    if (rest.cargoOrdUsr3 > 0) ord += 4;

    let typeCondition = {};
    if (type === "cargo") {

        typeCondition = {
            cargoSellClntNo: rest.cargoSellClntNo,
            ord: ord
        };

    } else if (type === "cont") {

        const odrNo = ed_odrNo.getValue().toUpperCase();
        typeCondition = {
            ord: ord,
            cargoSrchCnd: cargoSrchTyp == 5 && odrNo != ""? odrNo : cargoSrchCnd,
            odrNo: cargoSrchTyp == 0 && odrNo != ""? odrNo : "",
            cntrNo: ed_cntrNo.getValue().toUpperCase(),
            impExpDomesticClsCd: lc_impExpDomesticClsCd.getValue()
        };

    }

    // 조회조건 JSON에 타입별 조회조건 JSON 추가
    Object.assign(retrieveCondition, typeCondition);

    dma_retrieve.setEmptyValue();
    dma_retrieve.setJSON(retrieveCondition);
};

/**
 * tabControl change
 */
scwin.tac_bulkCont_onchange = function (tabId, index, userTabId) {

    scwin.CargoType = userTabId;
    scwin.selectedLclRow = "";

    if (userTabId == "cargo") {

        grp_searchbox.hide();
        scwin.grdObj = gr_fl;

        scwin.search_cargo();

    } else if (userTabId == "cont") {

        grp_searchbox.show("");
        scwin.grdObj = gr_flc;

        scwin.search_cont();
    }

};

/**
 * ds_cond dataList
 */
scwin.ds_cond_ondataload = function() {

};

