    if (ds_edi.getTotalRow() == 0) return;

    const {odrNo,cntrSeq,wrkPathSeq,wrkStpSeq,cntrNo,dptWrkPlCd,arvWrkPlCd,dptWrkPlNm,arvWrkPlNm} = ds_edi.getRowJSON(0);

    var paramJson = {
        mdiTitle : "반출입정보EDI등록",
        crryoutEdiType : "",
        crryinEdiType : "",
        arrParam : [
            [
                ""
                , ""
                , odrNo
                , cntrSeq
                , wrkPathSeq
                , wrkStpSeq
                , ""
                , ""
                , ""
                , ""
                , ""
                , cntrNo
                , dptWrkPlCd
                , arvWrkPlCd
                , dptWrkPlNm
                , arvWrkPlNm
                , "CO"
                , "CO"
            ]
        ]
    };

    const opts = {
        id : "op_202_02_23p",	
        popupName : "반출입예정정보EDI등록",
        modal : true,
        type : "browserPopup",
        title : "반출입예정정보EDI등록",
        width : "1100",
        height : "850"
    }

    $c.win.openPopup("/ui/ds/op/wrkplan/transwrkplan/op_202_02_23p.xml", opts, paramJson);
    // "/ds/op/wrkplan/transwrkplan/op_202_02_21p.jsp?paramTitle=반출입예정정보EDI등록&crryoutEdiType=&crryinEdiType=";
};

/**
 * 최적차량
 */
scwin.showmb = function(flmaster, ton, dt) {

    const wfmObj = $p.parent().wfm_wframe2.getWindow();
    const array_data = flmaster.split("-");

    if (wfmObj.tac_car.getSelectedTabID() == "tab_car_mb") {
        // FootDiv4 최적차량 탭    
        wfmObj.scwin.showmbcar(ton, dt);

    } else if (wfmObj.tac_car.getSelectedTabID() == "tab_car_matching") {

        // FootDiv5
        wfmObj.scwin.showmbrequestcar(array_data[0], array_data[1], tac_bulkCont.getSelectedTabID());
    }

};

/**
 * 선택된 화물의 차량 찾기
 */
scwin.f_SearchCar = function(mode, row) {

    const wfmObj = $p.parent().wfm_wframe2.getWindow();
    const ds = mode == 'cargo'? ds_fl : ds_flc;
    let sub_ds, sub_gr;

    // 차량종류
    switch (scwin.vehclType) {
        case 'all'      : 
            sub_ds = wfmObj.dtl_car; 
            sub_gr = wfmObj.gr_car;
            break;
        case 'blk'      : 
            sub_ds = wfmObj.dtl_car_blk;
            sub_gr = wfmObj.gr_car_blk;
            break;
        case 'cntr'     : 
            sub_ds = wfmObj.dtl_car_cntr; 
            sub_gr = wfmObj.gr_car_cntr;
            break;
        case 'matching' : 
            sub_ds = wfmObj.dtl_car_matching; 
            // sub_gr = wfmObj.gr_car;
            break;
        case 'mb'       : 
            sub_ds = wfmObj.dtl_car_mb;
            sub_gr = wfmObj.gr_car_mb;
            break;
        case 'public'   : 
            break;
    }

    const vehclNo = ds.getCellData(row, "vehclNo");
    const alloccarDd = ds.getCellData(row, "alloccarDd");

    for(let i=0; i<sub_ds.getTotalRow(); i++) {
        const sub_vehclNo = sub_ds.getCellData(i, "vehclNo").replace(/-/g,'');
        const sub_mtvehclDd = sub_ds.getCellData(i, "mtvehclDd").replace(/-/g,'');

        if (vehclNo == sub_vehclNo && alloccarDd == sub_mtvehclDd) {

            // sub_ds.RowMark
            sub_gr.setRowBackgroundColor(i, "#fcf8e3");
            sub_gr.setRowColor(i, "black");
        }
    }
};

/**
 * ds_fl dataList
 */
scwin.ds_fl_ondataload = function () {

    if (ds_fl.getTotalRow() == 0) return;

	if (scwin.vehclType == "mb") {
        scwin.selectedvehclRow = ""; 
        scwin.ez110Idx = "";    // wfm_wframe2에서 전달해주는 차량등록번호
    }

    const {idx,wt,onDt,dmCoshippingNo} = ds_fl.getRowJSON(0);
    scwin.showmb(idx,wt,onDt);

    // as-is RowMark 대응    
    // 합적번호
    if ($c.util.isEmpty(dmCoshippingNo)) {

        // 선택한것처럼 보이게 
        gr_fl.setRowBackgroundColor(0, "#fcf8e3");
        gr_fl.setRowColor(0, "black");

    } else {

        // 동일 합적번호 focus 처리
        const matchArr = ds_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
        for(let i=0; i<matchArr.length; i++) {
            gr_fl.setRowBackgroundColor(matchArr[i], "#fcf8e3");
            gr_fl.setRowColor(matchArr[i], "black");
        }
    }

    let iTotalRows = 0;

    for(let i=0; i<ds_fl.getTotalRow(); i++) {
        let coshippingFlag = false;

        if (ds_fl.getCellData(i, "dmCoshippingNo") != "") {
            for(let j=0; j<ds_fl.getTotalRow(); j++) {

                if (i != j && ds_fl.getCellData(i, "dmCoshippingNo") == ds_fl.getCellData(j, "dmCoshippingNo")) {
                    coshippingFlag = true;
                    break;
                }
            }

            if (!coshippingFlag) iTotalRows = iTotalRows + 1;

        } else {
            iTotalRows = iTotalRows + 1;
        }
    }

    tbx_totalCargo.setValue(iTotalRows);

    scwin.f_SearchCar('cargo', 0);
};

/**
 * ds_flc dataList
 */
scwin.ds_flc_ondataload = function () {

};

/**
 * 벌크화물 onrowindexchange
 */
scwin.gr_fl_onrowindexchange = function (rowIndex, oldRow) {

    const {rmk, passout, gate} = ds_fl.getRowJSON(rowIndex);
    let label = "";

    if (!$c.util.isEmpty(rmk)) {
        label += "<span style='padding-left: 100px'><b>※ 비고내용</b> : <font color=red>" + rmk + "</font></span>"
    }

    if (!$c.util.isEmpty(gate)) {
        label += "<span style='padding-left: 100px'><b>※ 게이트정보</b> : " + gate + "</span>"
    }

    if (!$c.util.isEmpty(passout)) {
        label += "<span style='padding-left: 100px'><b>※ 경유지정보</b> : <font color=blue>상차지 → " + passout + " → 하차지</font></span>"
    }

    tbx_infoText.setValue(label);

};

/**
 * 벌크화물 oncellclick
 */
scwin.gr_fl_oncellclick = function (rowIndex, columnIndex, columnId) {

    const grdObj = gr_fl;

    scwin.selectedLclRow = rowIndex;

    const {rclntOrdNo, idx, wt, onDt} = ds_fl.getRowJSON(rowIndex);

    for(let i=0; i<ds_fl.getTotalRow(); i++) {

        grdObj.setRowReadOnly(i, true);

        // 그리드 초기화
        grdObj.setRowBackgroundColor(i, "");

        // 글자색 변경
        if (ds_fl.getCellData(i, "statuss") === "대기") {
            grdObj.setRowColor(i, "blue");
        } else {
            grdObj.setRowColor(i, "black");
        }
    }

    if (scwin.vehclType == "mb") {
        scwin.selectedvehclRow = ""; 
        scwin.ez110Idx = "";    // wfm_wframe2에서 전달해주는 차량등록번호
    }

    scwin.showmb(idx, wt, onDt);

    // as-is RowMark 대응
    // 동일 합적번호 배열
    const matchArr = ds_fl.getMatchedIndex("rclntOrdNo", rclntOrdNo, true);
    if (matchArr.length > 0) {
        for(let i=0; i<matchArr.length; i++) {
            grdObj.setRowBackgroundColor(matchArr[i], "#fcf8e3");
            grdObj.setRowColor(matchArr[i], "black");
        }
    } else {
        // 동일한 합적번호가 없는 경우
        grdObj.setRowBackgroundColor(rowIndex, "#fcf8e3");
    }

    scwin.f_SearchCar('cargo', rowIndex);

};

/**
 * 벌크화물 oncelldblclick
 */
scwin.gr_fl_oncelldblclick = function (rowIndex, columnIndex, columnId) {


    scwin.openPopup(ds_fl, rowIndex, "cargo");
};

/**
 * 컨테이너 oncellclick
 */
scwin.gr_flc_oncellclick = function (rowIndex, columnIndex, columnId) {

    const {idx, wt, onDt} = ds_flc.getRowJSON(rowIndex);

    scwin.selectedLclRow = rowIndex;

    if (scwin.vehclType == "mb") {
        scwin.selectedvehclRow = ""; 
        scwin.ez110Idx = "";    // wfm_wframe2에서 전달해주는 차량등록번호
    }

    scwin.showmb(idx, "", onDt);
    scwin.f_SearchCar('cntr',rowIndex);
};

/**
 * 컨테이너 oncelldblclick
 */
scwin.gr_flc_oncelldblclick = function (rowIndex, columnIndex, columnId) {
   return;
    scwin.openPopup(ds_flc, rowIndex, "cont");
};

/**
 * grid cell double click - popup open
 */
scwin.openPopup = function(dlt, rowIndex, type) {


    const {idx,statuss} = dlt.getRowJSON(rowIndex);

    let sUrl, popupName, height;

    const data = {
        CargoType: type,
        idx: idx
    }

    if (idx != "") {

        if (statuss == "대기") {
            sUrl = "/ui/bp/fbp/op/ac/ez_202_01_01p.xml";
            popupName = "운송의뢰화면";
            height = 840;
        } else {
            sUrl = "/ui/bp/fbp/op/ac/ez_202_01_01b.xml";
            popupName = "화물정보화면"
            height = type == "cargo"? 710 : 840;
        }

        let opts = {
              popupName: popupName
            , width: 1250
            , height: height
            , top: "0px"
            , left: "0px"
        }

        $c.win.openPopup(sUrl, opts, data);

    }
};

