/**
 * 배차 버튼 클릭
 */
scwin.showopcar = function (e) {

    if ($c.util.isEmpty(scwin.selectedLclRow)) {
        $c.win.alert("화물 정보가 선택되지 않았습니다.");
        return;
    }

    if (scwin.ez110Idx == "") {
        $c.win.alert("차량 정보가 선택되지 않았습니다.");
        return;
    }

    const url = "/ui/bp/fbp/op/ac/ez_208_01_05p.xml";

    const data = {
        cCase : tac_bulkCont.getSelectedTabID(),
        pFrame : $p.getFrame().id,
        sFrame : $p.parent().wfm_wframe2.id
    };

    const opts = {
        id : "ez_208_01_05p",	
        popupName : "화물배차",
        modal : true,
        type : "browserPopup",
