/**
 * 배차취소 버튼 클릭
 */
scwin.cancelop = async function (e) {

    if ($c.util.isEmpty(scwin.selectedLclRow)) {
        $c.win.alert("화물 정보가 선택되지 않았습니다.");
        return;
    }

    if (await $c.win.confirm("배차를 취소하시겠습니까?")) {

        const type = tac_bulkCont.getSelectedTabID();
        let vFlFlag = "";
        let vFlIdxs = "";

        if (type == "cargo") {
            vFlFlag = "1";

            // 합적번호가 같은 row
            // 합적번호가 없으면 선택된 row
            const dmCoshippingNo = ds_fl.getCellData(scwin.selectedLclRow, "dmCoshippingNo");

            if ($c.util.isEmpty(dmCoshippingNo)) {
                vFlIdxs += ds_fl.getCellData(scwin.selectedLclRow, "idx") + ',';
            } else {

                const matchArr = ds_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
                for(let i=0; i<matchArr.length; i++) {
                    vFlIdxs += ds_fl.getCellData(matchArr[i], "idx") + ',';
                }
            }


        } else if (type == "cont") {
            vFlFlag = "2";

            vFlIdxs += ds_flc.getCellData(scwin.selectedLclRow, "idx") + ',';
        }

        vFlIdxs = vFlIdxs.substring(0, vFlIdxs.length - 1); // 쉼표 제거

        ds_ApplyAlloccarCancel.removeAll();
        ds_ApplyAlloccarCancel.reform();

        var loop = vFlIdxs.replaceAll("-", ",").split(",");

        for(let i=0; i<loop.length; i += 2) {
            let iRow = ds_ApplyAlloccarCancel.insertRow();

            ds_ApplyAlloccarCancel.setCellData(iRow, "flIdxs", loop[i]);
            ds_ApplyAlloccarCancel.setCellData(iRow, "flFlag", vFlFlag);
            ds_ApplyAlloccarCancel.setCellData(iRow, "flDtlIdxs", loop[i + 1]);
            ds_ApplyAlloccarCancel.setCellData(iRow, "userId", $c.data.getMemInfo("userId"));

        }

        $c.sbm.execute(sbm_ApplyAlloccarCancel);

    }
};

/**
 * 배차취소 callback
 */
scwin.sbm_ApplyAlloccarCancel_submitdone = function(e) {
    if (e.responseJSON.resultDataSet[0].Code == 0) {
        const msg = ds_Result.getCellData(0, "outMsg");
        if (!$c.util.isEmpty(msg)) {
            $c.win.alert(msg).then(() => {
                scwin.reflashdata();
            });
        }
    }
};

/**
 * 화물삭제 버튼 클릭
 */
scwin.deletefl = async function (e) {

    if ($c.util.isEmpty(scwin.selectedLclRow)) {
        $c.win.alert("화물 정보가 선택되지 않았습니다.");
        return;
    }

    if (await $c.win.confirm("선택한 화물을 삭제하시겠습니까?")) {

        const type = tac_bulkCont.getSelectedTabID();
        const msg = "[TMS오류]배차된 화물을 삭제할 수 없습니다. 배차 취소 후 삭제 가능합니다.";

        let vFlFlag = "";
        let vFlIdxs = "";
        let vDmOrdNo = "";

        if (type == "cargo") {

            vFlFlag = "1";

            // 합적번호가 같은 row
            // 합적번호가 없으면 선택된 row
            const dmCoshippingNo = ds_fl.getCellData(scwin.selectedLclRow, "dmCoshippingNo");

            if ($c.util.isEmpty(dmCoshippingNo)) {

                if (ds_fl.getCellData(scwin.selectedLclRow, "statuss") != "대기") {
                    $c.win.alert(msg).then(() => {
                        scwin.reflashdata();
                    })
                    return;
                }

                vFlIdxs += ds_fl.getCellData(scwin.selectedLclRow, "idx") + ',';
                vDmOrdNo += ds_fl.getCellData(scwin.selectedLclRow, "dmOrdNo") + ',';

            } else {

                const matchArr = ds_fl.getMatchedIndex("dmCoshippingNo", dmCoshippingNo, true);
                for(let i=0; i<matchArr.length; i++) {

                    if (ds_fl.getCellData(matchArr[i], "statuss") != "대기") {
                        $c.win.alert(msg).then(() => {
                            scwin.reflashdata();
                        })
                        return;
                    }

                    vFlIdxs += ds_fl.getCellData(matchArr[i], "idx") + ',';
                    vDmOrdNo += ds_fl.getCellData(matchArr[i], "dmOrdNo") + ',';
                }
            }

        } else if (type == "cont") {

            vFlFlag = "2";

            vFlIdxs += ds_flc.getCellData(scwin.selectedLclRow, "idx") + ',';
            vDmOrdNo += ds_flc.getCellData(scwin.selectedLclRow, "dmOrdNo") + ',';

        }

        vFlIdxs = vFlIdxs.substring(0, vFlIdxs.length - 1); // 쉼표 제거
        vDmOrdNo = vDmOrdNo.substring(0, vDmOrdNo.length - 1); // 쉼표 제거

        ds_AlloccarFlDelete.removeAll();
        ds_AlloccarFlDelete.reform();

        var loop = vFlIdxs.replaceAll("-", ",").split(",");

        for(let i=0; i<loop.length; i += 2) {
            let iRow = ds_AlloccarFlDelete.insertRow();

            ds_AlloccarFlDelete.setCellData(iRow, "flIdxs", loop[i]);
            ds_AlloccarFlDelete.setCellData(iRow, "flFlag", vFlFlag);
            ds_AlloccarFlDelete.setCellData(iRow, "flDtlIdxs", loop[i + 1]);
            ds_AlloccarFlDelete.setCellData(iRow, "dmOrdNo", vDmOrdNo[i]);

        }

        $c.sbm.execute(sbm_AlloccarFlDelete);
    }

};

