/**
 * 조회조건 - 기간 세팅
 */
scwin.set_dateByType = function(type) {
    return scwin.f_eventRadioClick(type);
};

/**
 * 조회조건 - 기간 세팅(당일 / 금주 / 금월 / 전월 / 지정)
 */
scwin.f_eventRadioClick = function(type) {

    const rtnJson = {};
    const toDate = $c.date.getServerDateTime("yyyyMMdd");

    switch (type) {

        // 당일
        case '1': {

            rtnJson.gsVl3 = toDate;
            rtnJson.gsVl4 = toDate;

            break;
        }

        // 금주
        case '2': {

            const range = scwin.getWeekRangeSunToSat(new Date());

            rtnJson.gsVl3 = range.sDt1;
            rtnJson.gsVl4 = range.sDt2;

            break;
        }

        // 금월
        case '3': {

            const yyyyMM = toDate.slice(0, 6);

            // 조회 시작일
            rtnJson.gsVl3 = `${yyyyMM}01`;

            // 조회 종료일				
            rtnJson.gsVl4 = `${yyyyMM}${$c.date.getLastDateOfMonth(yyyyMM)}`;

            break;
        }

        // 전월
        case '4': {

            // 조회 시작일
            rtnJson.gsVl3 = $c.date.getDateAddMonthDirection(toDate, "-1", "F");

            // 조회 종료일				
            rtnJson.gsVl4 = $c.date.getDateAddMonthDirection(toDate, "-1", "L");

            break;
        }

        // 지정
        case '5': {
            break;
        }
    }

    return rtnJson;
};

/**
 * 금주 세팅
 */
scwin.getWeekRangeSunToSat = function(date) {
    function pad2(n) {
        return (n < 10 ? "0" : "") + n;
    }
    function yyyymmdd(d) {
        return d.getFullYear() + pad2(d.getMonth() + 1) + pad2(d.getDate());
    }
    var d = date ? new Date(date.getTime()) : new Date();
    var day = d.getDay(); // 0(일)~6(토)

    var sun = new Date(d);
    sun.setDate(d.getDate() - day);

    var sat = new Date(d);
    sat.setDate(d.getDate() + (6 - day));

    return { sDt1: yyyymmdd(sun), sDt2: yyyymmdd(sat) };
};

