/**
 * selectbox filter
 */
scwin.setFilter = function(filterValue) {

    const userId = $c.data.getMemInfo("userId");  //사용자ID

    if (userId === "acecorea") {

        ds_fl.clearFilter();

        // 배차여부
        const carAllocGub = lc_carAllocGub.getValue();
        if (carAllocGub == "2") { // 배차

            const fn_filter = function(cellData, tmpParam, rowIdx){
                if (cellData == "" ||
                    cellData == "경남81아1810" || cellData == "부산95아2673" || cellData == "경기82바3542" ||
                    cellData == "서울82바5050" || cellData == "대구81아6064" || cellData == "부산90자6112" ||
                    cellData == "부산90아7131" || cellData == "경남90자8670" || cellData == "대구80아9804") {
                    return false;
                }
                return true;
            };

            ds_fl.setColumnFilter({type:"func", colIndex:"vehclNo", key:fn_filter, condition:"and"});

        } else if (carAllocGub == "1") { // 미배차

            const fn_filter = function(cellData, tmpParam, rowIdx){
                if (cellData == "") {
                    return true;
                }
                return false;
            };

            ds_fl.setColumnFilter({type:"func", colIndex:"vehclNo", key:fn_filter, condition:"and"});
        }

        // 지사
        filterValue = lc_cargoGub.getValue();
        const fn_filter = function(cellData, tmpParam, rowIdx){
            if (cellData == filterValue || $c.util.isEmpty(filterValue)) {
                return true;
            }
            return false;   // return이 true인 경우 적용하고 false인 경우 넘김
        };

        ds_fl.setColumnFilter({type:"func", colIndex:"lobranNm", key:fn_filter, condition:"and"});

    } else {

        if ($c.util.isEmpty(filterValue)) {
            ds_fl.clearFilter();
            return;
        }

        const fn_filter = function(cellData, tmpParam, rowIdx){
            if (cellData == filterValue) {
                return true;
            }
            return false;   // return이 true인 경우 적용하고 false인 경우 넘김
        };

        ds_fl.clearFilter();
        ds_fl.setColumnFilter({type:"func", colIndex:"lobranNm", key:fn_filter, condition:"and"});

    }

    // total row
    tbx_totalCargo.setValue(ds_fl.getAllFilteredJSON().length);

};

