/**
 * 컨테이너 - [COPINO전송] - EDI 사전정보조회
 */
scwin.btn_transCopino_onclick = async function (e) {
    if (ds_flc.getTotalRow() == 0) return;

    let ret;
    const row = ds_flc.getRowPosition();
    const {odrNo,cntrSeq,wrkPathSeq,wrkStpSeq,wrkStpCd,dptWrkPlCd,arvWrkPlCd,vehclNo,dmOrd} = ds_flc.getRowJSON(row);

    const currTime = $c.date.getServerDateTime("yyyyMMddHHmm").substring(8, 12);
    if (currTime > "1730" && (dptWrkPlCd == "6C01" || arvWrkPlCd == "6C01")) {
        $c.win.alert("17시 30분 이후에는 KBCTCY의 요청으로 EDI 전송을 할 수 없습니다.");
        return false;
    }

    if (vehclNo == "") {
        $c.win.alert("운송차량이 없습니다");
        return false;
    }

    if (dmOrd == "") {
        $c.win.alert("동부오더가 아닙니다");
        return false;
    } else {

        const odrNoSub = odrNo.substring(1, 3);

        if (dptWrkPlCd == "6C01" || arvWrkPlCd == "6C01") {
            if (odrNoSub == "C2" && wrkStpCd == "0002" && wrkStpSeq == "20") {
                let condition = {
                    odrNo: odrNo
                    , cntrSeq: cntrSeq
                    , wrkPathSeq: wrkPathSeq
                    , wrkStpSeq: wrkStpSeq
                }

                dma_common.setEmptyValue();
                dma_common.setJSON(condition);
                $c.sbm.setAction(sbm_common, "/ncall.bp.fbp.op.ac.RetrievePreEdiInfoCMD.do");
                ret = await $c.sbm.execute(sbm_common)

                if (ret.responseJSON.resultDataSet[0].Code == 0) {
                    ds_edi.setJSON(ret.responseJSON.GAUCE);
                }

            } else {
                $c.win.alert("수입 풀반출 이외에는 직접 COPINO전송을 할수없습니다.\n동부 담당 배차게 문의요망!!");
                return false;
            }
        } else {

            const condition = {
                odrNo: odrNo
                , cntrSeq: cntrSeq
                , wrkPathSeq: wrkPathSeq
                , wrkStpSeq: wrkStpSeq
            }

            dma_common.setEmptyValue();
            dma_common.setJSON(condition);
            $c.sbm.setAction(sbm_common, "/ncall.bp.fbp.op.ac.RetrievePreEdiInfoCMD.do");
            ret = await $c.sbm.execute(sbm_common);

            if (ret.responseJSON.resultDataSet[0].Code == 0) {
                ds_edi.setJSON(ret.responseJSON.GAUCE);
            }
        }

    }
};

