/**
 * 벌크화물 excel download
 */
scwin.gridToExcel = function() {

    // row bgcolor 때문에 따로 지정
    for(let i=0; i<ds_fl.getTotalRow(); i++) {
        if (i % 2 === 0) {
            gr_fl.setRowBackgroundColor(i, "");
        } else {
            gr_fl.setRowBackgroundColor(i, "#f5fff5");
        }

        gr_fl.setRowColor(i, "black");

        const statuss = ds_fl.getCellData(i, "statuss");
        if (statuss === "대기") {
            gr_fl.setRowColor(i, "blue");
        } else {
            gr_fl.setRowColor(i, "black");
        }
    }

    const excelTitle = "벌크화물목록";
    const options = {
        fileName : `${excelTitle}.xlsx`,
        sheetName : excelTitle,
        bodyWordwrap : true,
        evenRowBackgroundColor : "#f5fff5"
    };

    $c.data.downloadGridViewExcel(gr_fl, options);
};

/**
 * 벌크화물 column move
 */
scwin.gr_fl_onbeforecolumnmove = function (info) {
    const {startColumnID,startColumnIndex,endColumnID,endColumnIndex} = info;
    const noMoveArr = ["regDd", "col1", "dmOrdNo", "rclntOrdNo"];

    if (noMoveArr.includes(startColumnID)) {
        return false;
    }

    if (endColumnIndex < 5) {
        return false;
    }

};

/**
 * 컨테이너 column move
 */
scwin.gr_flc_onbeforecolumnmove = function (info) {
    const {startColumnID,startColumnIndex,endColumnID,endColumnIndex} = info;
    const noMoveArr = ["line", "cntrNo", "onPos", "offPos"];

    if (noMoveArr.includes(startColumnID)) {
        return false;
    }

    if (endColumnIndex < 4) {
        return false;
    }
};

/**
 * 컨테이너 오더번호 validate
 */
scwin.ed_odrNo_onkeyup = function (e) {
    scwin.validAlphaNum(this, 2, 11);
};

/**
 * 컨테이너 컨테이너번호 validate
 */
scwin.ed_cntrNo_onkeyup = function (e) {
    scwin.validAlphaNum(this, 4, 7);
};

/**
 * validate onkeyup
 */
scwin.validAlphaNum = function(obj, alphaLen, numLen) {
    let val = obj.getValue();

    if (!val) {
        return;
    }

    val = val.toUpperCase();
    val = val.replace(/[^A-Z0-9]/g, "");

    let result = "";

    for(let i = 0; i < val.length; i++) {
        const ch = val.charAt(i);

        if (i < alphaLen) {
            if (/[A-Z]/.test(ch)) {
                result += ch;
            }
        } else {
            if (/[0-9]/.test(ch)) {
                result += ch;
            }
        }
    }

    const maxLen = alphaLen + numLen;

    if (result.length > maxLen) {
        result = result.substring(0, maxLen);
    }

    if (obj.getValue() !== result) {
        obj.setValue(result);
    }
};

/**
 * 컨테이너 오더번호 onkeypress
 */
scwin.ed_odrNo_onkeypress = function (e) {
    scwin.validKeypress(this, e, 2);
};

/**
 * 컨테이너 컨테이너번호 onkeypress
 */
scwin.ed_cntrNo_onkeypress = function (e) {
    scwin.validKeypress(this, e, 4);
};

/**
 * validate onkeypress
 */
scwin.validKeypress = function(obj, event, alphaLen) {
    const val = obj.getValue().toUpperCase();

    // 현재 영문 개수
    const letters = val.match(/^[A-Z]*/)[0];

    // 영문 입력 차단
    if (letters.length >= alphaLen && /[A-Za-z]/.test(event.key.toUpperCase())) {
        event.preventDefault(); // 입력 자체 차단
    }

    // 숫자 입력 차단
    if (val.length < alphaLen && /[0-9]/.test(event.key)) {
        event.preventDefault(); // 입력 자체 차단
    }

};
